const { NewsToMarkdownConverter } = require('./dist/index.js');
const { writeFile, mkdir } = require('fs/promises');
const { join } = require('path');

/**
 * 通用测试方法：给定一个链接，生成 Markdown
 * 
 * 使用方法：
 * node test-url.js <url> [options]
 * 
 * 示例：
 * node test-url.js "https://www.toutiao.com/article/123"
 * node test-url.js "https://www.toutiao.com/article/123" --download-images
 * node test-url.js "https://www.toutiao.com/article/123" --download-images --output-dir ./my-output
 */

async function testUrl() {
  // 解析命令行参数
  const args = process.argv.slice(2);
  
  if (args.length === 0 || args[0] === '--help' || args[0] === '-h') {
    console.log(`
使用方法：
  node test-url.js <url> [options]

参数：
  url                    要转换的文章 URL（必需）

选项：
  --no-download-images   不下载图片（默认会下载）
  --output-dir <dir>     输出目录（默认：./test-output）
  --no-metadata          不包含元数据
  --verbose              显示详细日志

示例：
  # 基础转换
  node test-url.js "https://www.toutiao.com/article/123"
  
  # 不下载图片
  node test-url.js "https://www.toutiao.com/article/123" --no-download-images
  
  # 指定输出目录
  node test-url.js "https://www.toutiao.com/article/123" --output-dir ./my-article
  
  # 显示详细日志
  node test-url.js "https://www.toutiao.com/article/123" --verbose
`);
    process.exit(0);
  }

  const url = args[0];
  const downloadImages = !args.includes('--no-download-images');
  const noMetadata = args.includes('--no-metadata');
  const verbose = args.includes('--verbose');
  
  // 获取输出目录
  let outputDir = './test-output';
  const outputDirIndex = args.indexOf('--output-dir');
  if (outputDirIndex !== -1 && args[outputDirIndex + 1]) {
    outputDir = args[outputDirIndex + 1];
  }

  console.log('=== News to Markdown 测试 ===\n');
  console.log(`URL: ${url}`);
  console.log(`下载图片: ${downloadImages ? '是' : '否'}`);
  console.log(`输出目录: ${outputDir}`);
  console.log(`包含元数据: ${!noMetadata ? '是' : '否'}`);
  console.log(`详细日志: ${verbose ? '是' : '否'}\n`);

  const converter = new NewsToMarkdownConverter();

  try {
    // 确保输出目录存在
    await mkdir(outputDir, { recursive: true });

    // 转换文章
    const result = await converter.convert({
      url,
      downloadImages,
      outputDir: downloadImages ? outputDir : undefined,
      verbose,
    });

    console.log('\n=== 转换结果 ===');
    console.log(`✓ 转换成功`);
    console.log(`\n元数据：`);
    console.log(`  标题: ${result.metadata.title}`);
    console.log(`  作者: ${result.metadata.author || '未知'}`);
    console.log(`  平台: ${result.metadata.platform || '通用'}`);
    console.log(`  发布时间: ${result.metadata.publishTime || '未知'}`);
    console.log(`  图片总数: ${result.metadata.imageCount}`);
    
    if (downloadImages) {
      console.log(`  已下载图片: ${result.metadata.downloadedImages || 0} 张`);
      console.log(`  封面图: ${result.metadata.coverImage || '无'}`);
      console.log(`  本地封面: ${result.metadata.localCoverPath || '无'}`);
    }
    
    console.log(`  内容长度: ${result.metadata.contentLength} 字符`);

    // 保存 Markdown
    const filename = downloadImages ? 'article.md' : `article-${Date.now()}.md`;
    const outputPath = join(outputDir, filename);
    await writeFile(outputPath, result.markdown);
    console.log(`\n✓ Markdown 已保存到: ${outputPath}`);

    if (downloadImages && result.metadata.downloadedImages > 0) {
      console.log(`✓ 图片已保存到: ${join(outputDir, 'images')}/`);
    }

    // 显示 Markdown 预览
    console.log('\n=== Markdown 预览（前 500 字符）===');
    console.log(result.markdown.substring(0, 500));
    if (result.markdown.length > 500) {
      console.log('...\n');
    }

    console.log('\n=== 测试完成 ===');

  } catch (error) {
    console.error('\n❌ 错误:', error.message);
    if (verbose) {
      console.error('\nStack trace:');
      console.error(error.stack);
    }
    process.exit(1);
  }
}

// 运行测试
testUrl().catch(error => {
  console.error('Fatal error:', error);
  process.exit(1);
});
